import { useEffect, useMemo, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import type { InterestTab as TagTab } from "@sitin/api-proto/gen/archat_api/user_api";
import Layout from "@/components/Layout";
import NavigationBar from "@/components/NavigationBar";
import Button from "@/components/Button";
import TagSelector, { type TagGroup, countSelectedTags } from "./TagSelector";
import { useTag } from "@/hooks/useTag";
import { useUser } from "@/hooks/useUser";
import Spinner from "@/components/Spinner";

import { toast } from "@/utils/toast";
import { goBack } from "@/utils/navigation";
import SkipTaskButton from "@/pages/ProfileTask/SkipTaskButton";
import { PERCENT_BY_STEP, getTaskNextPath, getTaskPrevPath, getTaskStep } from "@/pages/ProfileTask/taskMode";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

const MAX_SELECTED = 5;

export default function Tags() {
  const navigate = useNavigate();
  const location = useLocation();
  const taskMode = (location.state as { taskMode?: boolean } | null)?.taskMode === true;
  const step = getTaskStep(location.pathname);
  const nextPath = getTaskNextPath(location.pathname);
  const prevPath = getTaskPrevPath(location.pathname);
  const { userInfo, updateProfile } = useUser();
  const { tagTabs, refreshTags } = useTag();
  const [selectedList, setSelectedList] = useState<TagTab[]>(userInfo?.interestTabs ?? []);
  const [isSaving, setIsSaving] = useState(false);

  const selectedCount = countSelectedTags(selectedList);
  const isSaveDisabled = selectedCount === 0 || selectedCount > MAX_SELECTED || isSaving;

  useEffect(() => {
    refreshTags();
    // 埋点：兴趣标签页面展示
    if (taskMode) {
      bpTrack(EventName.pwa_profile_task_interest_tag_show);
    }
    bpTrack(EventName.pwa_onboarding_interest_tag_page_shown);
  }, [refreshTags, taskMode]);

  useEffect(() => {
    if (userInfo?.interestTabs) {
      setSelectedList(userInfo.interestTabs);
    }
  }, [userInfo?.interestTabs]);

  const list: TagGroup[] = useMemo(() => {
    return tagTabs.map((item) => ({
      key: item.key ?? "defaultKey",
      name: item.key ?? "Other",
      tags: item.tags ?? [],
    }));
  }, [tagTabs]);

  const handleSave = async () => {
    if (!userInfo || isSaving) return;

    setIsSaving(true);
    try {
      await updateProfile({
        interests: selectedList,
      });

      // 埋点：兴趣标签提交（不传参数，与 react-haven 保持一致）
      if (taskMode) {
        bpTrack(EventName.pwa_profile_task_interest_tag_continue, {
          tags: selectedList.toString(),
        });
      }
      bpTrack(EventName.pwa_onboarding_interest_tag_page_submit);
      bpTrack(EventName.pwa_profile_update_success, { field: "interests" });

      toast.success("Saved");
      if (taskMode) {
        navigate(nextPath, { state: { taskMode: true } });
      } else {
        goBack(navigate);
      }
    } catch {
      toast.error("Save failed. Please try again.");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Layout showTabBar={false}>
      <div className="relative flex h-full flex-col bg-surface">
        <div className="shrink-0 bg-surface">
          <NavigationBar
            onBack={() =>
              taskMode
                ? navigate(prevPath, prevPath === "/" ? { replace: true } : { state: { taskMode: true } })
                : goBack(navigate, "/")
            }
            rightSlot={taskMode ? <SkipTaskButton to={nextPath} /> : null}
          />
          {/* 任务模式显示进度条 */}
          {taskMode ? (
            <div className="h-1 w-full bg-white">
              <div
                className="h-full bg-[#6bc4ff] transition-all duration-300"
                style={{
                  width: `${PERCENT_BY_STEP[step as 0 | 1 | 2] ?? PERCENT_BY_STEP[0]}%`,
                }}
              />
            </div>
          ) : null}
          <div className="text-center mt-4 pb-2">
            <h1 className="text-xl font-bold capitalize text-brand-dark">What&apos;re You Into?</h1>
            <p className="mt-1 text-[15px] text-[#159cd7]">Pick up to {MAX_SELECTED} tags to show on your profile</p>
          </div>
        </div>

        {/* 可滚动内容区域 */}
        {list.length > 0 ? (
          <div className="flex-1 overflow-y-auto mt-4">
            <TagSelector
              list={list}
              selectedList={selectedList}
              onChange={setSelectedList}
              maxSelected={MAX_SELECTED}
            />
          </div>
        ) : (
          <div className="flex flex-1 items-center justify-center">
            <Spinner />
          </div>
        )}

        {/* Bottom Save Button */}
        <div
          className="fixed inset-x-0 bottom-0 flex h-[150px] items-start justify-center px-8 pt-[60px]"
          style={{
            background: "linear-gradient(180deg, rgba(239, 248, 255, 0) 0%, #eff8ff 58.67%)",
          }}
        >
          <Button onClick={handleSave} disabled={isSaveDisabled} variant="primary">
            {isSaving ? "Saving..." : taskMode ? "Next" : "Save"}
          </Button>
        </div>
      </div>
    </Layout>
  );
}
